import{_ as e,c as o,o as s,a1 as a}from"./chunks/framework.DDNAyvCW.js";const r="/assets/host_bastion_create.jOSwBR9t.png",g=JSON.parse('{"title":"Add Bastion Host","description":"","frontmatter":{},"headers":[],"relativePath":"docs/hosts/add-bastion.md","filePath":"docs/hosts/add-bastion.md"}'),n={name:"docs/hosts/add-bastion.md"};function d(i,t,c,h,u,l){return s(),o("div",null,t[0]||(t[0]=[a('<h1 id="add-bastion-host" tabindex="-1">Add Bastion Host <a class="header-anchor" href="#add-bastion-host" aria-label="Permalink to &quot;Add Bastion Host&quot;">​</a></h1><h2 id="bastion-host-resources" tabindex="-1">Bastion Host Resources <a class="header-anchor" href="#bastion-host-resources" aria-label="Permalink to &quot;Bastion Host Resources&quot;">​</a></h2><p>Bastion host resources are enterprise-level asset resources, usually synchronized from a bastion system.</p><h2 id="add-a-bastion-host" tabindex="-1">Add a Bastion Host <a class="header-anchor" href="#add-a-bastion-host" aria-label="Permalink to &quot;Add a Bastion Host&quot;">​</a></h2><p><img src="'+r+'" alt=""></p><p>Click the <strong>Asset Management</strong> button and fill in the bastion host configuration.</p><table tabindex="0"><thead><tr><th>Field</th><th>Description</th><th>Required</th></tr></thead><tbody><tr><td><strong>Device Type</strong></td><td>For bastion assets, select <code>Server/Bastion</code></td><td>Yes</td></tr><tr><td><strong>Connection IP/URL</strong></td><td>Enter the target host IP address or domain name</td><td>Yes</td></tr><tr><td><strong>Port</strong></td><td>SSH service port, default is <code>22</code></td><td>Yes</td></tr><tr><td><strong>Username</strong></td><td>SSH login username</td><td>Yes</td></tr><tr><td><strong>Key</strong></td><td>Select the authentication key required by the bastion host</td><td>Yes</td></tr><tr><td><strong>Password</strong></td><td>Authentication password required by the bastion host</td><td>Yes</td></tr><tr><td><strong>SSH Proxy</strong></td><td>Configure SSH proxy here if a proxy server is needed for the connection</td><td>No</td></tr><tr><td><strong>Alias</strong></td><td>A human-friendly name to identify the host</td><td>Yes</td></tr><tr><td><strong>Group</strong></td><td>Select or enter the group this host belongs to (e.g. <code>development</code>, <code>production</code>)</td><td>No</td></tr></tbody></table><h2 id="sync-bastion-assets" tabindex="-1">Sync Bastion Assets <a class="header-anchor" href="#sync-bastion-assets" aria-label="Permalink to &quot;Sync Bastion Assets&quot;">​</a></h2><p>On the bastion resource page, you can view the list of added bastion hosts. Click the <strong>Refresh</strong> button of a bastion host to manually sync the latest asset information.</p><p>Organization assets are used in the same way as personal assets. Click an asset item to establish a connection. You can also use the context menu to add favorites, add notes, or assign custom groups.</p><h2 id="custom-group-management" tabindex="-1">Custom Group Management <a class="header-anchor" href="#custom-group-management" aria-label="Permalink to &quot;Custom Group Management&quot;">​</a></h2><p>In the workspace, select the <strong>Bastion Resources</strong> tab and click the <strong>Custom Group</strong> button in the upper-right corner to create a custom group:</p><ul><li><strong>Group Name</strong>: Enter the group name</li><li><strong>Group Description</strong>: Enter the group description (optional)</li></ul><p>On the bastion resource page, you can edit or delete a custom group from its context menu.</p>',14)]))}const m=e(n,[["render",d]]);export{g as __pageData,m as default};
